INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Topic-based threading$q$, $q$Every message is filed under a named topic within a stream, keeping parallel conversations organized and easy to follow later.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Open source and self-hostable$q$, $q$The full codebase is open source, so teams can self-host for data control or use Zulip Cloud without vendor lock-in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Cross-platform apps$q$, $q$Native apps are available for web, Windows, macOS, Linux, iOS, and Android.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Powerful search$q$, $q$Full-text search across streams, topics, and message history helps teams retrieve past decisions and context quickly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$API, bots, and integrations$q$, $q$A REST API, webhooks, and prebuilt bots connect Zulip to common developer and business tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Async-first design$q$, $q$The interface is built to support distributed teams working across time zones rather than assuming everyone is online at once.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Enterprise administration$q$, $q$Higher tiers add SSO, data export, and administrative controls suited to larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Sponsored free plans$q$, $q$Zulip sponsors free Cloud plans for qualifying open-source projects, nonprofits, researchers, and educational institutions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Topic threading preserves context far better than flat channel-based chat once conversation volume grows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Fully open source, so teams can self-host for complete data control or move between hosting options freely$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Generous free tier plus sponsored free plans for open-source, nonprofit, and education use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Designed specifically for asynchronous, distributed teams rather than always-on real-time chat$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Backed by a dedicated nonprofit foundation focused on the project's long-term sustainability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Topic-based threading has a learning curve for teams used to Slack's simpler channel model$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Smaller third-party app and integration marketplace compared to Slack or Microsoft Teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Mobile and desktop app polish can lag behind larger, better-funded competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$The 2026 transition to nonprofit foundation ownership adds some uncertainty around long-term product pace$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$What is Zulip?$q$, $q$Zulip is an open-source team chat application that organizes conversations into topic-based threads, designed to keep distributed and asynchronous teams focused and organized.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Is Zulip free to use?$q$, $q$Yes. Zulip offers a free Zulip Cloud tier and a completely free self-hosted option, alongside paid Cloud and self-hosted plans with additional features and support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Can I self-host Zulip?$q$, $q$Yes. Zulip's full codebase is open source, so organizations can deploy and manage their own Zulip server instead of using the hosted Cloud service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$How is Zulip different from Slack?$q$, $q$Zulip's defining difference is topic-based threading, where every message belongs to a named topic within a channel, which keeps parallel conversations organized in a way flat channel chat does not.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Who owns Zulip now?$q$, $q$Zulip is stewarded by the nonprofit Zulip Foundation, formed in 2026, with Kandra Labs continuing as the primary development team.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Does Zulip offer free plans for nonprofits or open source projects?$q$, $q$Yes. Zulip sponsors free Cloud plans for more than 1,000 qualifying organizations, including open-source projects, educators, researchers, and nonprofits.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$What platforms does Zulip support?$q$, $q$Zulip provides apps for web browsers, Windows, macOS, Linux, iOS, and Android.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Does Zulip integrate with other tools?$q$, $q$Yes. Zulip offers a REST API, incoming and outgoing webhooks, and a library of bots for integrating with other developer and business tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Distributed software teams$q$, $q$Engineering teams spread across time zones use Zulip's topic threading to keep async technical discussions organized and easy to catch up on.$q$, $q$Software and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Open-source project communication$q$, $q$Open-source communities use Zulip to manage high-volume, public discussion without losing track of individual topics or contributors.$q$, $q$Open-source maintainers and contributors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Academic and course discussions$q$, $q$Universities and online courses use Zulip to structure student and instructor discussion by topic, keeping course material organized across a term.$q$, $q$Educators and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Cloud Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Core topic-threaded messaging","Web, desktop, and mobile apps","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Cloud Standard$q$, $q$$6.67 per user per month (annual) or $8 monthly$q$, $q$monthly or annual$q$, NULL, $q$["Full searchable message history","Expanded integrations","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Cloud Plus$q$, $q$$10 per user per month (annual) or $12 monthly$q$, $q$monthly or annual$q$, NULL, $q$["Advanced administration controls","SCIM provisioning","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Self-Hosted Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Self-managed deployment","Community support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$Self-Hosted Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Large-scale self-managed deployments","Custom SLAs","Dedicated enterprise support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$overview$q$, $q$What Is Zulip$q$, 2, ARRAY[$q$Zulip is an open-source team chat platform built around a topic-based threading model. Instead of one continuous stream of messages per channel, every conversation lives inside a named topic within a stream, so unrelated discussions never blend together.$q$, $q$The project started in 2012, was acquired and later open-sourced by Dropbox, and has since been developed by Kandra Labs and, as of 2026, the nonprofit Zulip Foundation. Because the codebase is fully open source, organizations can run Zulip on their own infrastructure or use the hosted Zulip Cloud service.$q$, $q$Zulip is aimed at teams that value organized, searchable, asynchronous communication over the fast, ephemeral feel of typical chat apps, making it popular with software teams, open-source projects, research groups, and educational institutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zulip's core feature is topic threading: every message belongs to a topic within a stream, keeping parallel conversations legible even in high-volume channels.$q$, $q$It ships with desktop, web, and mobile apps, a REST API, incoming and outgoing webhooks, and a library of bots and integrations for connecting to other developer and business tools.$q$, $q$Administrators get self-hosting flexibility, data export, and migration tools between self-managed and cloud deployments, along with enterprise controls like SSO and audit logging on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zulip Cloud has three tiers: a Free plan, a Standard plan at $6.67 per user per month billed annually, and a Plus plan at $10 per user per month billed annually, with slightly higher monthly-billed rates.$q$, $q$Self-hosted users can run the software entirely free, or subscribe to Basic, Business, or Enterprise self-hosted support plans that unlock features like read receipts, unlimited message history, and priority support.$q$, $q$Pricing is based purely on the number of active users, and the Zulip Foundation sponsors free access for open-source projects, nonprofits, researchers, and educators.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c920ff4f-292d-4b70-82c4-92886a22daa0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora Billing$q$, $q$Flexible billing engine supporting subscription, usage-based, and hybrid pricing models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora Revenue$q$, $q$Automated revenue recognition built to support GAAP and IFRS compliance requirements.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora Payments$q$, $q$Global payment processing with built-in fraud protection for recurring transactions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora Collections$q$, $q$AI-powered dunning and cash recovery tools to reduce failed payments and churn.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora CPQ$q$, $q$Configure-price-quote tooling integrated with Salesforce for recurring revenue sales deals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Zuora AI Paywalls$q$, $q$No-code tools for personalizing subscriber pricing pages and offers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Usage-based pricing support$q$, $q$Native handling of consumption-based and hybrid pricing models alongside flat subscriptions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Enterprise integrations$q$, $q$Prebuilt connections to systems like Salesforce and NetSuite for end-to-end quote-to-cash workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$End-to-end quote-to-cash coverage in a single connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Strong support for complex, usage-based, and hybrid pricing models$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Recognized as a leader by major analyst firms for subscription management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Proven at scale with large enterprise customers across many industries$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Deep revenue recognition automation for regulatory compliance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Pricing is opaque and quote-based, making budgeting difficult for smaller companies$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Implementation and onboarding can be lengthy and often require specialized expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Total cost of ownership can be high, especially across multi-year enterprise contracts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Steep learning curve for teams new to enterprise subscription billing platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$What is Zuora used for?$q$, $q$Zuora is used by subscription and recurring-revenue businesses to manage billing, payments, revenue recognition, and quoting across the customer lifecycle.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$How much does Zuora cost?$q$, $q$Zuora does not publish list pricing; costs are set through a custom sales quote based on billing volume, subscriber count, and which modules a company needs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$What are Zuora's main products?$q$, $q$Zuora's core products are Zuora Billing, Zuora Revenue, Zuora Payments, Zuora Collections, Zuora CPQ, and Zuora AI Paywalls.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Who uses Zuora?$q$, $q$Zuora is used by mid-market and enterprise subscription businesses, including well-known companies like Zoom, Ford, Okta, and Salesforce.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Does Zuora support usage-based pricing?$q$, $q$Yes. Zuora natively supports usage-based and hybrid pricing models alongside traditional flat subscriptions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Is Zuora suitable for small businesses?$q$, $q$Zuora is generally built for mid-market and enterprise companies with complex billing needs; smaller businesses may find lighter, self-serve billing tools a better fit.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Does Zuora integrate with Salesforce?$q$, $q$Yes. Zuora CPQ integrates directly with Salesforce to connect sales quoting with billing and revenue processes.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$When was Zuora founded?$q$, $q$Zuora was founded in 2007 by Tien Tzuo along with K.V. Rao and Cheng Zou.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Complex hybrid billing$q$, $q$SaaS companies combining flat subscriptions with usage-based charges use Zuora Billing to manage pricing complexity in one system.$q$, $q$SaaS finance and billing operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Revenue recognition automation$q$, $q$Enterprise finance teams use Zuora Revenue to automate compliant revenue recognition under ASC 606 and IFRS 15.$q$, $q$Enterprise controllers and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Sales-to-billing alignment$q$, $q$Sales organizations use Zuora CPQ integrated with Salesforce to quote recurring deals that flow directly into billing without manual re-entry.$q$, $q$Enterprise sales operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Launch$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Core subscription billing for startups and MVPs","Standard integrations","Entry-level billing volume"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Scale$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Usage-based pricing support","Salesforce CPQ integration","Higher billing capacity and SSO"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Unlimited usage-based billing","Global multi-entity support","Custom SLAs and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$overview$q$, $q$What Is Zuora$q$, 2, ARRAY[$q$Zuora is an enterprise software platform built to help subscription and recurring-revenue businesses manage the entire quote-to-cash process, from pricing and quoting through billing, payments, collections, and revenue recognition.$q$, $q$Founded in 2007 and headquartered in Redwood City, California, Zuora has grown into a publicly traded company serving over 1,000 customers worldwide, including major names like Zoom, Ford, Okta, and Salesforce.$q$, $q$The platform is aimed primarily at finance and revenue operations leaders in SaaS and subscription businesses who need to support complex, evolving pricing models without stitching together multiple point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zuora Billing supports subscription, usage-based, and hybrid pricing models with the flexibility to change pricing structures as a business evolves.$q$, $q$Zuora Revenue automates revenue recognition for GAAP and IFRS compliance, while Zuora Payments and Zuora Collections handle global payment processing and AI-assisted cash recovery.$q$, $q$Zuora CPQ integrates with Salesforce to connect sales quoting directly to billing, and newer AI Paywalls tools let teams personalize subscriber offers without engineering support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6fe9497-6864-400b-8879-65cfc6655084', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zuora does not publish list pricing. Costs are determined through a sales quote based on factors like billing volume, subscriber count, contract length, and which product modules are included.$q$, $q$Third-party analyses describe an entry-level tier for startups and MVPs, a mid tier adding usage-based pricing and Salesforce CPQ integration for scale-ups, and an enterprise tier supporting unlimited usage-based billing for global operations.$q$, $q$Multi-year commitments typically come with discounted pricing, and total cost of ownership can be substantial for large enterprise deployments given implementation and support requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Drag-and-drop form builder$q$, $q$A visual editor for building forms with over 3,000 prebuilt templates across industries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Conditional logic and branching$q$, $q$Forms can dynamically show, hide, or branch fields based on prior answers for personalized multi-step flows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Payment integrations$q$, $q$Native support for PayPal, Stripe, Square, and other processors to collect payments directly through forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$HIPAA and GDPR compliance$q$, $q$Certified data handling practices designed for healthcare, education, and other regulated industries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Extensive integrations$q$, $q$Over 4,000 third-party connections available through native integrations and Zapier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Document generation$q$, $q$Ability to generate documents like invoices and contracts automatically from form submissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Advanced security controls$q$, $q$256-bit SSL encryption, single sign-on, custom roles, and audit trails for enterprise data governance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Form analytics$q$, $q$Built-in reporting to track submission volume, completion rates, and respondent behavior.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Very large template library speeds up form creation for common use cases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Strong compliance credentials, including HIPAA and GDPR, for regulated industries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Wide integration coverage reduces the need for custom development work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Handles complex, multi-step forms with conditional logic well$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Free plan available for basic use before committing to a paid tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Paid plans get relatively expensive quickly once advanced features are needed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Interface can feel less modern than some newer, design-forward form builder competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Enterprise pricing requires a custom quote, reducing upfront pricing transparency$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Some advanced compliance and integration features are gated behind higher-priced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$What is 123FormBuilder?$q$, $q$123FormBuilder is a cloud-based online form builder for creating surveys, registrations, order forms, and payment forms without coding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Is 123FormBuilder free?$q$, $q$Yes, 123FormBuilder offers a free Basic plan with submission limits, alongside paid Gold, Platinum, Diamond, and Enterprise tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Is 123FormBuilder HIPAA compliant?$q$, $q$Yes, 123FormBuilder offers HIPAA and GDPR compliant data handling, making it suitable for healthcare and other regulated industries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$What integrations does 123FormBuilder support?$q$, $q$123FormBuilder connects to more than 4,000 third-party tools through native integrations and Zapier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Who owns 123FormBuilder now?$q$, $q$123FormBuilder has been acquired by Kiteworks, a secure content governance and file-sharing company.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Can I accept payments through 123FormBuilder?$q$, $q$Yes, forms can collect payments directly through integrations with PayPal, Stripe, Square, and other processors.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$What was 123FormBuilder previously called?$q$, $q$The company originally launched as 123ContactForm in 2008 and rebranded to 123FormBuilder in 2017.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Does 123FormBuilder offer enterprise plans?$q$, $q$Yes, an Enterprise tier is available with a custom annual quote for organizations needing advanced compliance and support features.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$HIPAA-compliant patient intake$q$, $q$Healthcare organizations use 123FormBuilder to collect patient intake and consent data securely and in a compliant way.$q$, $q$Healthcare providers and administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Lead generation and event registration$q$, $q$Marketing teams build lead-capture and event registration forms with integrated payment collection.$q$, $q$Marketing and events teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Internal workflow automation$q$, $q$HR and operations teams automate approvals and internal data collection using conditional logic and document generation.$q$, $q$HR and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Basic$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Core drag-and-drop form builder","Limited monthly submissions","Access to template library"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Gold$q$, $q$$37 per month$q$, $q$monthly$q$, NULL, $q$["Higher submission limits","Payment integrations","Standard third-party integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Platinum$q$, $q$$49 per month$q$, $q$monthly$q$, NULL, $q$["Expanded submissions and storage","Advanced conditional logic","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Diamond$q$, $q$$99 per month$q$, $q$monthly$q$, NULL, $q$["Highest submission and storage limits","Advanced security controls","Document generation"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Dedicated compliance features","SSO and audit trails","Dedicated account support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$overview$q$, $q$What Is 123FormBuilder$q$, 2, ARRAY[$q$123FormBuilder is a cloud-based platform for building online forms, surveys, and payment collection pages without writing code. It was founded in 2008 in Timișoara, Romania, originally under the name 123ContactForm.$q$, $q$The company rebranded to 123FormBuilder in 2017 and has since been acquired by Kiteworks, a secure content and file-sharing company, giving the platform a strong emphasis on compliance and data security alongside its form-building tools.$q$, $q$It is used by more than 35,000 organizations worldwide, including enterprises like Airbus and the University of Oxford, spanning use cases from marketing lead capture to healthcare intake forms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers a drag-and-drop form editor with more than 3,000 templates, conditional logic for multi-step and branching forms, and mobile-responsive form output.$q$, $q$Payment collection is built in through PayPal, Stripe, Square, and other processors, and forms can connect to more than 4,000 external tools through native integrations or Zapier.$q$, $q$Security and compliance are a major focus, with HIPAA and GDPR certified data handling, SSL encryption, single sign-on, audit trails, and WCAG 2.1 accessibility support available on the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$123FormBuilder offers a free Basic plan for simple forms with limited submissions, alongside paid tiers named Gold, Platinum, and Diamond that unlock higher submission limits, more integrations, and expanded storage.$q$, $q$The Gold plan starts at $37 per month, with Platinum priced around $49 per month and Diamond around $99 per month, billed monthly.$q$, $q$An Enterprise tier is available for large organizations that need dedicated compliance features and support, priced through a custom annual quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('327d1ac7-d2d5-4c9f-85cd-79a59dd1b3a9', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Interest graph targeting$q$, $q$Aggregated social data into a Blended Interest Graph used to infer consumer interests for ad targeting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Social data aggregation$q$, $q$Pulled signals from platforms like Twitter and Foursquare to build audience profiles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Brand recommendation matching$q$, $q$Patented content-matching technology connected brands with relevant audience segments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Mobile and social ad focus$q$, $q$Targeting technology was built specifically for mobile and social advertising placements.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Acquired technology base$q$, $q$Core targeting technology was absorbed into AcuityAds' (now illumin's) advertising platform after acquisition.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Historically notable for pioneering interest-graph based social ad targeting in the early 2010s$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Backed by venture investors and acquired at a meaningful valuation, indicating real market traction at the time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Its technology and team continued to be used within its acquirer's platform rather than being shut down outright$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$No longer operates or is sold as an independent, standalone product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Its official domain no longer hosts current company information or a live signup flow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Modern buyers cannot evaluate or purchase 140 Proof directly, only its successor platform, illumin$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Public information about the brand is largely historical, with limited current documentation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$What was 140 Proof?$q$, $q$140 Proof was a social and mobile advertising technology company founded in 2009 that used an interest graph built from social data to power ad targeting and brand recommendations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Is 140 Proof still an active company?$q$, $q$No. 140 Proof was acquired by AcuityAds in 2016, and its technology and team were absorbed into AcuityAds, which itself rebranded to illumin in 2023. It does not operate as a standalone product today.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Who acquired 140 Proof?$q$, $q$AcuityAds, a Canadian advertising technology company, acquired 140 Proof in August 2016 for up to $20 million.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$What happened to the 140 Proof website?$q$, $q$The 140proof.com domain now redirects toward pages associated with its acquirer's corporate site rather than an independent product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$What is illumin, and how does it relate to 140 Proof?$q$, $q$Illumin is the current brand name of AcuityAds, the company that acquired 140 Proof in 2016; 140 Proof's targeting technology and team were folded into that company.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Who founded 140 Proof?$q$, $q$140 Proof was founded in 2009 by Jon Elvekrog and John Manoogian III.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Can I still sign up for 140 Proof today?$q$, $q$No. There is no current signup flow or active product under the 140 Proof name; interested buyers would need to look at illumin instead.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Historical ad-tech research$q$, $q$Marketers and researchers studying the evolution of interest-based social ad targeting can reference 140 Proof as an early example of the approach.$q$, $q$Ad-tech researchers and marketing historians$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Understanding illumin's origins$q$, $q$Buyers evaluating illumin's current advertising platform can better understand its roots by learning about the 140 Proof acquisition.$q$, $q$Advertisers evaluating illumin$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$Due diligence on acquired brands$q$, $q$Analysts researching AcuityAds and illumin's acquisition history use 140 Proof as a case study in ad-tech consolidation.$q$, $q$Investors and industry analysts$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$overview$q$, $q$What Was 140 Proof$q$, 2, ARRAY[$q$140 Proof was an advertising technology company founded in 2009 in San Francisco, California, that specialized in social and mobile ad targeting based on users' interests inferred from social media activity.$q$, $q$Its core technology, sometimes referred to as a Blended Interest Graph, aggregated social signals from platforms like Twitter and Foursquare to help brands target ads and recommendations based on inferred consumer interests.$q$, $q$The company was acquired by AcuityAds in 2016 for up to $20 million, and its team and technology were integrated into AcuityAds' broader advertising platform rather than continuing as an independently branded product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$key-features$q$, $q$What It Offered Historically$q$, 2, ARRAY[$q$140 Proof's core offering was interest-based ad targeting, using patented content-matching technology to connect brands with relevant audiences based on social data rather than traditional demographic targeting alone.$q$, $q$It served advertisers and publishers looking to reach mobile and social media users with more relevant ad creative and recommendations.$q$, $q$Following its acquisition, these targeting capabilities were absorbed into AcuityAds' platform, which itself later rebranded fully to illumin in 2023.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3329d28-c04e-48fd-acb5-e4086d15cfec', $q$pricing$q$, $q$Current Status and Pricing$q$, 2, ARRAY[$q$140 Proof does not operate as an independent, purchasable product today, so there is no current public pricing to report.$q$, $q$The 140proof.com domain redirects through pages associated with its acquirer's corporate site rather than hosting a standalone product or signup flow.$q$, $q$Businesses seeking similar interest-based social and mobile ad targeting capabilities today would need to evaluate illumin or other current demand-side advertising platforms directly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Unlimited free DNS zones$q$, $q$Register and manage as many DNS zones as needed at no cost, with no artificial account limits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Full standard record support$q$, $q$Supports A, AAAA, CAA, CNAME, MX, SRV, TXT, and SSHFP record types.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$DNSSEC support$q$, $q$Cryptographically signed DNS zones help protect against DNS spoofing and cache poisoning.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$TLSA and DANE support$q$, $q$Supports TLSA records for DANE-based TLS certificate validation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Dynamic DNS$q$, $q$Useful for home servers or connections where the public IP address changes regularly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Web request forwarding$q$, $q$Allows domain redirects to be configured directly through DNS management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$No purchase requirement$q$, $q$Available to anyone regardless of whether they use 1984's other hosting products.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Long uptime track record$q$, $q$1984 reports roughly two decades of consistent uptime for the FreeDNS service.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Completely free with no zone or domain limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Backed by an established, privacy-focused Icelandic hosting company operating since 2006$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Supports advanced records like DNSSEC and TLSA not always found in free DNS tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Long-standing, reliable uptime track record$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$No requirement to be a paying 1984 hosting customer to use it$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$No formal SLA or dedicated paid support tier specifically for FreeDNS$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Interface is more utilitarian than modern, design-forward DNS dashboards$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$As a free service, support responsiveness may be slower than with paid DNS providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Lacks advanced enterprise features like GeoDNS or load-balancing based DNS responses found in commercial DNS platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$What is FreeDNS by 1984?$q$, $q$FreeDNS is a free authoritative DNS hosting and management service offered by the Icelandic hosting company 1984, letting anyone manage DNS records for their domains at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Is FreeDNS really free?$q$, $q$Yes, FreeDNS has no cost and no limit on the number of DNS zones a user can register and manage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Do I need to be a 1984 hosting customer to use FreeDNS?$q$, $q$No, FreeDNS is available to anyone and does not require purchasing any other 1984 hosting product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Does FreeDNS support DNSSEC?$q$, $q$Yes, FreeDNS supports DNSSEC for cryptographically signed DNS zones, along with TLSA records for DANE-based certificate validation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Can I use FreeDNS for dynamic DNS?$q$, $q$Yes, FreeDNS supports dynamic DNS, which is useful for home servers or connections with changing IP addresses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$How many domains can I add to FreeDNS?$q$, $q$There is no stated limit; users can register and manage as many DNS zones as they like.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Who runs FreeDNS?$q$, $q$FreeDNS is operated by 1984, an Icelandic web hosting company founded in 2006 and based in Reykjavík.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Is FreeDNS reliable?$q$, $q$1984 reports approximately two decades of consistent uptime for the FreeDNS service.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Free DNS for personal and small business domains$q$, $q$Individuals and small businesses use FreeDNS to manage DNS records for their domains without paying for a commercial DNS provider.$q$, $q$Individuals and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Dynamic DNS for home labs$q$, $q$Self-hosting enthusiasts use FreeDNS's dynamic DNS support to keep domains pointed at home servers with changing IP addresses.$q$, $q$Home lab and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$Privacy-focused DNS hosting$q$, $q$Privacy-conscious users choose 1984's FreeDNS to keep their DNS management with a provider outside major US cloud platforms.$q$, $q$Privacy and free-speech focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$FreeDNS$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited DNS zones","All standard DNS record types","DNSSEC and TLSA support","Dynamic DNS and web forwarding"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$overview$q$, $q$What Is 1984 FreeDNS$q$, 2, ARRAY[$q$1984 is an Icelandic web hosting company founded in 2006, known for its focus on privacy, free speech, and renewable-energy-powered infrastructure. FreeDNS is the company's free authoritative DNS hosting product.$q$, $q$FreeDNS lets anyone register and manage DNS zones for their domains at no cost, without requiring them to purchase any other 1984 hosting service.$q$, $q$The service is aimed at individuals, small businesses, and technically minded users who want reliable, full-featured DNS management outside of the major commercial cloud DNS providers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreeDNS supports an unlimited number of DNS zones per account and covers standard record types including A, AAAA, CAA, CNAME, MX, SRV, TXT, and SSHFP.$q$, $q$It also supports DNSSEC for signed, tamper-resistant DNS responses and TLSA records for DANE-based certificate validation, features not always found in free DNS tools.$q$, $q$Dynamic DNS support makes it useful for home servers with changing IP addresses, and web request forwarding allows simple domain redirects without additional infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f6d592e-573c-4bf8-a2a8-9b49d9c69d60', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$FreeDNS is entirely free, with no zone limits and no requirement to purchase other 1984 hosting products.$q$, $q$1984 funds the free service through revenue from its paid web hosting, VPS, and managed enterprise hosting offerings.$q$, $q$There is no paid tier specifically for FreeDNS, and no published SLA beyond the company's stated long-term uptime track record.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$AI Content Builder$q$, $q$Helps subject matter experts turn knowledge into interactive courses and scenarios while L&D retains oversight.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Collaborative learning model$q$, $q$Enables peer feedback and expert-driven content creation rather than only top-down course design.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$AI Companion$q$, $q$Delivers personalized content recommendations and real-time coaching on mobile and desktop.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Skills gap analysis$q$, $q$Analyzes learner performance data to detect skill gaps and recommend relevant training.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$HRIS and HCM integrations$q$, $q$Connects with more than 80 systems, including Workday, SAP, BambooHR, and Slack.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Compliance training tools$q$, $q$Supports certification tracking and automated reporting for regulatory compliance training.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Multi-audience platform$q$, $q$Serves employee, customer, and partner training needs from a single platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$L&D community resources$q$, $q$Access to The L&D Collective community and L&D Performance Academy certification program.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Strong collaborative learning model driven by internal subject matter experts rather than only top-down courses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$AI content tools speed up course creation for non-instructional-designers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Wide native integrations with major HR and HCM systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Highly rated on review platforms and recognized as a leading LMS and AI LMS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Serves multiple training audiences, including employees, customers, and partners, from one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Full pricing for Business and Enterprise tiers is not publicly listed and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Can be more complex to set up than simple, single-purpose LMS tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$The collaborative model requires cultural buy-in from subject matter experts to be fully effective$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Higher price point than very basic e-learning tools for small teams with simple needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$What is 360Learning?$q$, $q$360Learning is an AI-powered collaborative learning platform that combines LMS and LXP capabilities for onboarding, compliance, and skills training.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$How much does 360Learning cost?$q$, $q$The Team plan starts at $8 per user per month for up to 100 users, while Business and Enterprise pricing is custom-quoted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Is there a free trial?$q$, $q$Yes, 360Learning offers a 30-day free trial with no setup fees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$What integrations does 360Learning support?$q$, $q$It integrates with more than 80 HRIS and HCM systems, including Workday, SAP, BambooHR, and Slack.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Who founded 360Learning?$q$, $q$360Learning was founded in 2013 in Paris, France, by Nick Hernandez and Guillaume Alary.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$What is collaborative learning?$q$, $q$Collaborative learning is 360Learning's approach where subject matter experts within an organization help create and refine training content alongside the L&D team.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Does 360Learning support compliance training?$q$, $q$Yes, the platform includes compliance training tools with certification tracking and automated reporting.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$What companies use 360Learning?$q$, $q$Customers include Cisco, Duolingo, Michelin, LVMH, Safran, and Cognizant, among more than 2,500 organizations.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Employee onboarding and compliance$q$, $q$HR and L&D teams use 360Learning to standardize onboarding and track mandatory compliance training completion.$q$, $q$HR and L&D teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Sales enablement$q$, $q$Sales enablement teams build and continuously update training content with input from top-performing sales reps.$q$, $q$Sales enablement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Customer and partner training$q$, $q$Customer education teams train external users and partners on product usage from the same platform used for employees.$q$, $q$Customer education and partner enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Team$q$, $q$$8 per user per month$q$, $q$monthly$q$, NULL, $q$["Up to 100 users","AI Content Builder","Core collaborative learning features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Business$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Advanced HRIS integrations","Skills analytics","Single sign-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Unlimited scale","Dedicated support","Custom security and compliance controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$overview$q$, $q$What Is 360Learning$q$, 2, ARRAY[$q$360Learning is an AI-powered learning platform founded in 2013 in Paris, France, combining LMS and learning experience platform (LXP) capabilities in one product.$q$, $q$The company pioneered collaborative learning, an approach where subject matter experts inside an organization help create and refine training content, rather than relying only on a centralized L&D team.$q$, $q$It serves more than 2,500 organizations globally, including large enterprises like Cisco, Duolingo, and Michelin, and has raised roughly $240 million in funding to support its growth.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$360Learning's AI Content Builder helps internal experts turn their knowledge into interactive courses and scenarios while L&D teams retain oversight and quality control.$q$, $q$Its Data and Insights tools analyze learner performance, detect skill gaps, recommend relevant courses, and automate reporting for L&D and HR leaders.$q$, $q$The platform integrates with more than 80 HRIS and HCM systems, including Workday, SAP, and BambooHR, and supports multiple training audiences, from employees to customers and partners, on a single platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54a8da3e-0766-4538-be06-7648eb552e9a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$360Learning's Team plan starts at $8 per user per month, billed monthly, and covers up to 100 active users with no hidden setup fees or minimum volume commitments.$q$, $q$Business and Enterprise tiers are priced through a custom sales quote based on company size, integration needs, and scope of use.$q$, $q$A 30-day free trial is available for organizations wanting to evaluate the platform before committing to a paid plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Three-column snippet boards$q$, $q$Organize code snippets visually using a three-column board layout.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Cloud storage and access$q$, $q$Snippets are stored in the cloud and accessible from any device with an internet connection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Real-time collaboration$q$, $q$Boards can be shared privately with individuals or teams for collaborative editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Broad language support$q$, $q$Supports syntax highlighting and organization for roughly 140 programming languages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Browser extension$q$, $q$Captures code blocks directly from web pages being browsed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$VSCode extension$q$, $q$Lets developers insert, update, and create 3Cols snippets, including shared team snippets, from inside the editor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Progressive Web App support$q$, $q$Installable as a standalone app on Windows and Android in addition to browser use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Free sharing and storage$q$, $q$No charge to store, access, or share snippets or boards.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Completely free to use for storing, accessing, and sharing snippets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Real-time collaborative boards make team snippet sharing straightforward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$VSCode and browser extensions integrate snippet capture into existing developer workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Simple, visual three-column layout keeps snippets organized without complex folder structures$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Works as an installable Progressive Web App across desktop and mobile$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Small, independently run project with limited public information about its backing or roadmap$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Fewer integrations and enterprise features than larger snippet managers such as GitHub Gist or dedicated snippet tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$No visible paid tier raises questions about the long-term sustainability of the free service$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Limited third-party reviews and community size compared to mainstream developer tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$What is 3Cols?$q$, $q$3Cols is a free cloud-based code snippet manager that organizes snippets into shareable, three-column boards.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Is 3Cols free?$q$, $q$Yes, 3Cols is free to use for storing, accessing, and sharing code snippets, with no publicly advertised paid tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Does 3Cols have a VSCode extension?$q$, $q$Yes, an official VSCode extension called 3ColsVSCode lets developers insert, update, and create snippets directly from their editor.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Can I share snippets privately with my team on 3Cols?$q$, $q$Yes, boards can be shared privately with individuals or teams for real-time collaborative editing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$How many programming languages does 3Cols support?$q$, $q$3Cols supports syntax highlighting and organization for roughly 140 programming languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Is 3Cols a project management tool?$q$, $q$No. Despite the name suggesting a column-based workflow tool, 3Cols is a code snippet manager; its name refers to the three-column layout used to organize snippets.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Does 3Cols have a browser extension?$q$, $q$Yes, a browser extension lets users capture code blocks directly from web pages they are viewing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Who built 3Cols?$q$, $q$3Cols is built by independent developer Oli Blade; public details about the company behind it are limited.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Personal snippet organization$q$, $q$Individual developers use 3Cols to organize reusable code snippets across personal projects.$q$, $q$Individual developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Team snippet collaboration$q$, $q$Small development teams use shared 3Cols boards to collaboratively build and maintain a library of boilerplate code.$q$, $q$Small development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Capturing code while browsing$q$, $q$Developers use the browser extension to quickly save code blocks found on documentation sites, blogs, or Stack Overflow.$q$, $q$Developers researching code online$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited snippet boards","Real-time collaboration","Browser and VSCode extensions","Support for roughly 140 languages"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$overview$q$, $q$What Is 3Cols$q$, 2, ARRAY[$q$3Cols is a free, cloud-based code snippet manager that helps developers store, organize, and share reusable code snippets. Its name comes from the three-column board layout used to organize snippets, not from any kanban or project management functionality.$q$, $q$Snippets are stored in the cloud and accessible from any device, and boards can be shared privately with individuals or teams for real-time collaborative editing.$q$, $q$The tool is built by independent developer Oli Blade, and public information about the company behind it, such as a founding year or headquarters, is limited, suggesting it is a small or independently run project.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$3Cols organizes code into three-column boards with support for roughly 140 programming languages and syntax highlighting.$q$, $q$A browser extension lets users capture code snippets directly from web pages, while an official VSCode extension allows inserting, updating, and creating 3Cols snippets from inside the code editor.$q$, $q$The web app is built as a Progressive Web App, so it can be installed as a standalone application on Windows and Android in addition to running in a browser.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b8bdf64-831a-4991-928c-9915966c425d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$3Cols is completely free, with no cost to store, access, or share snippets.$q$, $q$No paid tier or premium plan is publicly advertised on the platform.$q$, $q$This makes it accessible to individual developers or small teams without any billing commitment.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$API gateway$q$, $q$Provides traffic control, rate limiting, and access policy enforcement for APIs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$API program management$q$, $q$Centralizes analytics, access control, and monetization oversight for API programs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Developer portal$q$, $q$Lets organizations publish APIs and onboard internal or external developer consumers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$OpenShift and Kubernetes integration$q$, $q$Built for containerized, microservices-based deployment on Red Hat OpenShift and Kubernetes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Hybrid cloud deployment$q$, $q$Supports deployment in the cloud, on-premise, or a combination of both.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$API monetization$q$, $q$Enables usage-based billing and monetization models for API products.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Security controls$q$, $q$Includes authentication, authorization, and encryption for API traffic.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Part of Red Hat Integration$q$, $q$Integrated with Red Hat's broader middleware and integration product suite.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Mature, proven API management platform backed by Red Hat's enterprise support and ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Strong hybrid cloud and OpenShift integration for containerized and microservices architectures$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Comprehensive feature set spanning gateway, analytics, developer portal, and monetization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Backed by a large, established vendor for long-term product stability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$No self-serve public pricing; requires contacting Red Hat sales for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Best suited to enterprises already invested in Red Hat and OpenShift, less appealing for small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$More complex to deploy and manage than lightweight, cloud-native API gateways$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$The independent 3scale brand no longer operates separately, fully folded into Red Hat's product naming and portals$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$What is 3scale?$q$, $q$3scale is an API management platform originally founded in 2007, now sold and developed by Red Hat as Red Hat 3scale API Management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Is 3scale still an independent company?$q$, $q$No. 3scale was acquired by Red Hat in 2016 and now operates fully as part of Red Hat's product portfolio.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$How much does 3scale cost?$q$, $q$Red Hat does not publish self-serve pricing for 3scale; customers must contact Red Hat sales for a custom quote.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Does 3scale work with Kubernetes or OpenShift?$q$, $q$Yes, 3scale integrates closely with Red Hat OpenShift and Kubernetes for containerized, microservices-based deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$What happened to 3scale.net?$q$, $q$The original 3scale.net domain now redirects to Red Hat's Red Hat 3scale API Management product page.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Who founded 3scale?$q$, $q$3scale was co-founded by Steven Willmott and Martin Tantow in 2007 in Barcelona, Spain.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$What does 3scale do for API monetization?$q$, $q$3scale provides tools for tracking API usage and enabling usage-based billing and monetization of API products.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Is 3scale open source?$q$, $q$3scale offers an open-source API gateway component, while the full management platform is sold as a commercial Red Hat product with paid support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Enterprise API governance$q$, $q$Enterprises use Red Hat 3scale to manage internal and partner-facing APIs across hybrid and multi-cloud environments.$q$, $q$Enterprise platform and integration teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Microservices API management$q$, $q$Platform teams running microservices on OpenShift or Kubernetes use 3scale for integrated API gateway and analytics functionality.$q$, $q$Platform engineering teams using Kubernetes or OpenShift$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$API monetization programs$q$, $q$Companies selling API access as a product use 3scale's developer portal and usage-based billing tools to manage external API consumers.$q$, $q$Companies monetizing APIs as a product$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$Red Hat 3scale API Management$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["API gateway and traffic control","Developer portal","Analytics and monetization","Hybrid cloud deployment","Red Hat enterprise support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$overview$q$, $q$What Is 3scale$q$, 2, ARRAY[$q$3scale was an independent API management company founded in 2007 in Barcelona, Spain, that built tools for securing, publishing, analyzing, and monetizing APIs.$q$, $q$After a partnership beginning in 2015, Red Hat acquired 3scale in 2016, and the product now operates as Red Hat 3scale API Management, part of the Red Hat Integration suite.$q$, $q$The original 3scale.net website now redirects to Red Hat's product pages, and Red Hat, which is itself owned by IBM, is now the sole vendor and support provider for the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform includes an API gateway for traffic control, rate limiting, and access policy enforcement, along with centralized program management covering analytics, access control, and monetization.$q$, $q$A developer portal helps organizations publish APIs and onboard internal or external developer consumers.$q$, $q$It supports hybrid cloud deployment models and integrates closely with Red Hat OpenShift and Kubernetes for containerized, microservices-based environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cd08476-3295-4d37-9113-84262b137477', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Red Hat 3scale API Management does not publish self-serve pricing on its product pages.$q$, $q$Prospective customers must contact Red Hat sales directly or use a product trial to obtain cost information.$q$, $q$Pricing is typically bundled into broader Red Hat enterprise subscription and support agreements rather than sold as a fully standalone product.$q$]::text[], 2);
