-- Enrichment marathon batch: Zulip, Zuora, 123FormBuilder, 140 Proof, 1984.is, 360Learning, 3Cols, 3scale

-- ── Zulip ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source team chat app that organizes every conversation into topic-based threads, built for focused, asynchronous communication across distributed teams.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Zulip Cloud Standard from $6.67 per user per month billed annually$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Small team, roughly 15 people across Kandra Labs and the nonprofit Zulip Foundation$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zulip Review: Features, Pricing, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Zulip offers in 2026: open-source, topic-threaded team chat with self-hosting options, Cloud pricing from free to Plus, and how it compares to Slack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zulip is an open-source team chat application distinguished by its topic-based threading model, which organizes every conversation into named threads within channels (called streams) rather than a single flat timeline. This structure lets distributed and asynchronous teams follow multiple parallel discussions without losing context, and it creates a searchable, organized archive of team knowledge as a byproduct of normal conversation. Zulip began in 2012 as a startup founded by Jeff Arnold, Waseem Daher, Jessica McKellar, and Tim Abbott, and was acquired by Dropbox in 2014. Dropbox open-sourced the project in 2015, after which Tim Abbott founded Kandra Labs in 2016 to continue commercial development. In 2026, Kandra Labs was donated to a newly formed independent nonprofit, the Zulip Foundation, which now stewards the project alongside Kandra Labs as its operating entity. The software remains 100 percent open source under an Apache 2.0 style license and can be self-hosted or run as a managed Zulip Cloud service. Zulip Cloud offers a Free tier, a Standard plan priced at $6.67 per user per month billed annually (or $8 billed monthly), and a Plus plan at $10 per user per month billed annually (or $12 monthly). Self-hosted deployments can run entirely free, on a Basic plan at $3.50 per user per month, on a Business plan matching Cloud Standard pricing, or on a custom-priced Enterprise plan for large-scale support needs. Pricing scales by active user count rather than feature access, and Zulip sponsors free plans for more than 1,000 qualifying organizations including open-source projects, nonprofits, researchers, and educators. Target users span software engineering teams, research groups, universities, open-source communities, and event organizers who need structured, searchable discussion rather than ephemeral chat. Zulip provides web, desktop (Windows, macOS, Linux), and mobile (iOS, Android) clients, along with a REST API, webhook integrations, and bots for connecting to other tools. Its main competitive differentiators against Slack and Microsoft Teams are first-class threading, full data portability through self-hosting, and an architecture explicitly designed for async, time-zone-distributed collaboration rather than always-on real-time chat.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c920ff4f-292d-4b70-82c4-92886a22daa0';

