-- ── 140 Proof ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Former social-interest mobile advertising and audience-targeting platform, acquired by AcuityAds in 2016 and now folded into the illumin advertising platform rather than operating as an independent product.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (historical, prior to acquisition)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$140 Proof: What Happened to This Ad-Tech Platform (2026 Update)$q$, seo_title),
  seo_meta_description = COALESCE($q$140 Proof was a social-interest mobile ad targeting company acquired by AcuityAds in 2016. See its history, what it did, and its status today under illumin.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$140 Proof was an advertising technology company launched in 2009 by Jon Elvekrog and John Manoogian III, headquartered in San Francisco, California. The company built patented content-matching technology that aggregated social data from platforms like Twitter and Foursquare into what it called a Blended Interest Graph, using that data to power interest-based mobile and social advertising targeting and recommendations for brands. It raised venture funding, including backing from BlueRun Ventures, and operated as a roughly 20-person team at the time of its acquisition. In August 2016, 140 Proof was acquired by AcuityAds, a Canadian advertising technology company, in an all-cash deal worth up to $20 million, structured with an initial payment plus earn-outs tied to performance. Following the acquisition, 140 Proof's leadership and team joined AcuityAds, and its targeting technology was absorbed into AcuityAds' broader advertising platform rather than continuing to operate as a standalone, separately branded product. In 2023, AcuityAds itself fully rebranded to illumin, retaining AcuityAds Holdings Inc. as its legal corporate name while doing business publicly as illumin, a self-serve, journey-based demand-side advertising platform. As of the current research, the 140proof.com domain no longer hosts an independent product; it redirects through illumin's parent corporate site, and there is no evidence that the 140 Proof brand is still marketed or sold as a distinct product. This tool listing is therefore historical in nature: 140 Proof represents a notable piece of 2010s-era social and mobile ad-tech history, illustrating the interest-graph approach to audience targeting that was common before increased platform data restrictions and privacy regulation reshaped the ad-tech industry, but it is not something a business could sign up for or purchase today as a standalone product. Anyone looking for its modern equivalent functionality, such as interest and behavioral targeting for social and mobile advertising, would need to evaluate illumin directly or other current demand-side platforms and social ad-targeting tools, since 140 Proof's original technology and team now operate under that later corporate identity rather than under the 140 Proof name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c3329d28-c04e-48fd-acb5-e4086d15cfec';

