-- ── 1984.is ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free DNS hosting and management service from Icelandic hosting provider 1984, offering unlimited DNS zones, dynamic DNS, and DNSSEC support at no cost.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Reykjavík, Iceland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Icelandic$q$]::text[],
  seo_title = COALESCE($q$1984 FreeDNS Review: Free DNS Hosting From Iceland (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what 1984's FreeDNS offers in 2026: unlimited free DNS zones, DNSSEC and dynamic DNS support, and how it fits into 1984's privacy-focused Icelandic hosting.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$1984 is an Icelandic web hosting company founded in 2006 by a group of free software and civil liberties enthusiasts, headquartered in Reykjavík. The company has grown into one of Iceland's largest hosting providers, built around a stated mission of privacy, freedom of speech, and 100 percent renewable energy use, and it holds ISO 27001 information security certification. This listing covers 1984's FreeDNS product specifically, a free authoritative DNS hosting and management service available to anyone, whether or not they are a paying 1984 hosting customer. FreeDNS lets users register and manage as many DNS zones as they like with no artificial limits, and it supports a full range of DNS record types including A, AAAA, CAA, CNAME, MX, SRV, TXT, and SSHFP records. It also supports more advanced, security-oriented DNS features such as DNSSEC for cryptographically signed zones and TLSA records used for DANE-based certificate validation, features that are not always available in free DNS offerings from other providers. Additional capabilities include dynamic DNS support, which is useful for home servers or connections with changing IP addresses, and web request forwarding for redirecting traffic from a domain. 1984 states that FreeDNS has maintained 100 percent uptime for roughly two decades, and the company funds the free service through revenue from its paid hosting, VPS, and managed enterprise hosting offerings rather than charging directly for DNS. Because FreeDNS requires no purchase commitment, it functions as a genuinely free, standalone DNS tool that users can adopt regardless of where their website or email is hosted. It is best suited to individuals, small businesses, and self-hosting or home-lab enthusiasts who want reliable, full-featured DNS management without a subscription, particularly those who value working with a privacy-focused provider outside the major US cloud DNS providers. It is less suited to enterprises needing advanced traffic-steering features like GeoDNS, load-balancing based DNS responses, or a formal paid SLA, since those capabilities and support guarantees are more commonly found in commercial DNS platforms such as Cloudflare, AWS Route 53, or NS1.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4f6d592e-573c-4bf8-a2a8-9b49d9c69d60';

