-- ── 360Learning ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered collaborative learning platform combining LMS and LXP capabilities for employee onboarding, compliance training, and skills development.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $8 per user per month (Team plan, billed monthly, up to 100 users)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$300-plus employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France, with additional offices in New York and London$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$360Learning Review: Features, Pricing, and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what 360Learning offers in 2026: AI-powered collaborative learning, LMS and LXP features, HRIS integrations, and pricing plans starting at $8 per user.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$360Learning is an AI-powered corporate learning platform founded in 2013 in Paris, France by Nick Hernandez and Guillaume Alary. The company has raised approximately $240 million in funding across multiple rounds, including a $200 million private equity round in 2021 led by Sumeru Equity Partners, SoftBank Vision Fund 2, and Silver Lake Waterman, with participation from existing investors Bpifrance Large Venture, XAnge, and Educapital. The company employs more than 300 people across offices in Paris, New York, and London and serves over 2,500 organizations, including Cisco, Duolingo, Michelin, LVMH, Safran, and Cognizant. 360Learning combines traditional learning management system (LMS) functionality with learning experience platform (LXP) capabilities, and it is built around what the company calls collaborative learning: enabling subject matter experts within an organization to create and refine training content directly, rather than relying solely on top-down instructional design. Key product capabilities include an AI Content Builder that helps non-instructional-designer employees turn expertise into interactive courses and scenarios while keeping L&D teams in an oversight role, a Data and Insights module that analyzes performance, detects skill gaps, recommends courses, and automates reporting, and an AI Companion that delivers personalized content recommendations and real-time coaching across mobile and desktop. The platform integrates with more than 80 HRIS and HCM systems, including Workday, SAP, BambooHR, and Slack, to sync employee and organizational data. Use cases span compliance training, employee onboarding, sales enablement, frontline staff training, and external customer or partner training, all served from a single platform that can support multiple audiences at once. 360Learning has been named a top LMS and AI LMS in industry rankings for 2026 and holds GDPR, ISO 27001, and SOC 2 certifications. The company also runs a community called The L&D Collective, with more than 4,000 members, and an L&D Performance Academy that has certified more than 6,000 learners. Pricing starts with a Team plan at $8 per user per month, billed monthly, covering up to 100 users, while Business and Enterprise tiers are sold through custom sales quotes based on scope and requirements; a 30-day free trial is available with no setup fees.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54a8da3e-0766-4538-be06-7648eb552e9a';

