-- ── 3scale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$API management platform for securing, publishing, and monetizing APIs across hybrid cloud, now developed and sold by Red Hat as Red Hat 3scale API Management.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Originally Barcelona, Spain; now part of Red Hat, headquartered in Raleigh, North Carolina, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$3scale Review: Red Hat API Management Platform (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what 3scale (now Red Hat 3scale API Management) offers in 2026: API gateway, developer portal, monetization, and hybrid cloud deployment features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$3scale is an API management platform originally co-founded in 2007 by Steven Willmott and Martin Tantow in Barcelona, Spain. The company launched a public beta in November 2008 and released its commercial product, 3scale Connect, in March 2009, offering both a self-serve version and a premium version with support and a service-level agreement. It grew through the early 2010s, raising $4.2 million in funding in March 2013 to expand functionality and international reach. 3scale and Red Hat began partnering in early 2015, building a joint solution that combined 3scale's API management with Red Hat's existing middleware portfolio, and in 2016 Red Hat fully acquired 3scale to strengthen its ability to manage the growing number of public and internal APIs being built on containers and microservices. Since the acquisition, 3scale has operated as Red Hat 3scale API Management, part of the broader Red Hat Integration product suite, and Red Hat itself is now a subsidiary of IBM. The original 3scale.net domain now redirects to Red Hat's product page, reflecting that 3scale no longer exists as an independently branded, separately sold company. Functionally, Red Hat 3scale API Management provides an API gateway for traffic control, rate limiting, and access policy enforcement; centralized API program management covering analytics, access control, and monetization; and a developer portal for publishing APIs and onboarding external or internal developers. It is built for hybrid cloud deployment, supporting cloud, on-premise, or combined environments, and integrates closely with Red Hat OpenShift and Kubernetes for organizations building containerized, microservices-based applications. Security capabilities include authentication, authorization, and encryption for API traffic. As part of Red Hat's enterprise portfolio, 3scale does not publish self-serve pricing; prospective customers must contact Red Hat sales or use a product trial to get cost information, and pricing is generally bundled into broader Red Hat subscription and support agreements. The platform is best suited to enterprises, particularly those already invested in Red Hat and OpenShift, that need a mature, well-supported API management layer spanning gateway, analytics, developer experience, and monetization, and is less suited to small teams or startups looking for a lightweight, self-serve, cloud-native API gateway.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0cd08476-3295-4d37-9113-84262b137477';

